// frontend/src/App.js
import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './contexts/AuthContext';

// Components
import Navbar from './components/common/Navbar';
import Footer from './components/common/Footer';

// Auth
import Login from './components/auth/Login';
import Register from './components/auth/Register';

// Jobs
import HomePage from './pages/HomePage';
import JobForm from './components/jobs/JobForm';
import JobDetails from './components/jobs/JobDetails';
import JobsPage from './pages/JobsPage';

// Workers
import WorkerProfile from './components/workers/WorkerProfile';
import WorkerDashboard from './components/workers/WorkerDashboard';

// Vouchers
import VoucherPurchase from './components/vouchers/VoucherPurchase';
import MyVouchers from './components/vouchers/MyVouchers';

// Admin
import AdminDashboard from './components/admin/AdminDashboard';

// Protected Route Component
const ProtectedRoute = ({ children, allowedTypes = [] }) => {
    const { user, isAuthenticated } = useAuth();

    if (!isAuthenticated) {
        return <Navigate to="/login" />;
    }

    if (allowedTypes.length > 0 && !allowedTypes.includes(user?.user_type)) {
        return <Navigate to="/" />;
    }

    return children;
};

function AppContent() {
    return (
        <div className="app">
            <Navbar />
            <Routes>
                {/* Public Routes */}
                <Route path="/" element={<HomePage />} />
                <Route path="/login" element={<Login />} />
                <Route path="/register" element={<Register />} />
                <Route path="/jobs" element={<JobsPage />} />
                <Route path="/jobs/:id" element={<JobDetails />} />
                <Route path="/workers/:id" element={<WorkerProfile />} />

                {/* Protected Routes */}
                <Route path="/jobs/post" element={
                    <ProtectedRoute>
                        <JobForm />
                    </ProtectedRoute>
                } />

                <Route path="/dashboard" element={
                    <ProtectedRoute>
                        {({ user }) => {
                            if (user?.user_type === 'worker') return <WorkerDashboard />;
                            if (user?.user_type === 'admin') return <AdminDashboard />;
                            return <Navigate to="/jobs" />;
                        }}
                    </ProtectedRoute>
                } />

                <Route path="/vouchers/buy" element={
                    <ProtectedRoute>
                        <VoucherPurchase />
                    </ProtectedRoute>
                } />

                <Route path="/vouchers/my" element={
                    <ProtectedRoute>
                        <MyVouchers />
                    </ProtectedRoute>
                } />

                <Route path="/admin/*" element={
                    <ProtectedRoute allowedTypes={['admin']}>
                        <AdminDashboard />
                    </ProtectedRoute>
                } />

                {/* 404 */}
                <Route path="*" element={<Navigate to="/" />} />
            </Routes>
            <Footer />
        </div>
    );
}

function App() {
    return (
        <Router>
            <AuthProvider>
                <AppContent />
            </AuthProvider>
        </Router>
    );
}

export default App;
